buffer.append(c.getQuery().toString(field));
buffer.append(")");
} else
buffer.append(c.getQuery().toString(field));

if (i != clauses.size()-1)
buffer.append(" ");
}

if (needParens) {
buffer.append(")");
}

if (getMinimumNumberShouldMatch()>0) {
buffer.append('~');
buffer.append(getMinimumNumberShouldMatch());
}

if (getBoost() != 1.0f)
{
buffer.append(ToStringUtils.boost(getBoost()));
}

return buffer.toString();
}

